import './App.css';
import { useState } from 'react';
import axios from 'axios';

import SchedulerForm from './components/SchedulerForm';
import SimulationBoard from './components/SimulationBoard';
import ResultsDisplay from './components/ResultsDisplay';

import FCFSChart from './components/FCFSchart';
import SSTFChart from './components/SSTFchart';
import SCANChart from './components/SCANchart';
import CSCANChart from './components/CSCANchart';

function App() {
  const [result, setResult] = useState(null);
  const [comparisonResult, setComparisonResult] = useState(null);
  const [selectedAlgorithm, setSelectedAlgorithm] = useState('fcfs');
  const handleCalculate = async (
  requests,
  head,
  algorithm,
  diskSize,
  direction
) => {
  try {
    const response = await axios.post(
      "http://127.0.0.1:8000/stimulate",
      {
        algorithm: algorithm,
        requests: requests,
        head: head,
        disk_size: diskSize,
        direction: direction
  }
    );

    setResult(response.data);
    setSelectedAlgorithm(algorithm);
  } 
  catch (error) 
  {
    console.error("API Error:", error);
    alert("Backend connection failed");
  }
};

  return (
    <div className="App" style={{ padding: '2rem' }}>
      <h1 className="heading">Job Scheduling Simulator</h1>

      <div className="container">
        {}
        <div className="form-section">
          <SchedulerForm onCalculate={handleCalculate} 
            onCompare={handleCompare}
            />
        </div>

        {}
        <div className="result-section">
          <SimulationBoard />

          {result && (
            <>
              <ResultsDisplay result={result} />

              {selectedAlgorithm === 'fcfs' && (
                <FCFSChart sequence={result.sequence} />
              )}
              {selectedAlgorithm === 'sstf' && (
                <SSTFChart sequence={result.sequence} />
              )}
              {selectedAlgorithm === 'scan' && (
                <SCANChart sequence={result.sequence} />
              )}
              {selectedAlgorithm === 'cscan' && (
                <CSCANChart sequence={result.sequence} />
              )}
              {selectedAlgorithm === 'look' && (
                <SCANChart sequence={result.sequence} />
              )}
            </>
          )}
          {comparisonResult && (
  <pre>
    {JSON.stringify(comparisonResult, null, 2)}
  </pre>
)}
        </div>
      </div>
    </div>
  );
  const handleCompare = async (
  requests,
  head,
  diskSize,
  direction
) => {

  try {

    const response = await axios.post(
      "http://127.0.0.1:8000/compare",
      {
        requests: requests,
        head: head,
        disk_size: diskSize,
        direction: direction
      }
    );

    setComparisonResult(response.data);

  } catch (error) {

    console.error("Compare API Error:", error);

    alert("Comparison failed");

  }
};
}

export default App;
